const verify = config => {
	console.log('Verifying config:', config);
	if('items' in config.resource || 'collections' in config.resource || 'tags' in config.resource) {
		if (!config.resource.library) {
			console.log('will throw');
			throw new Error('Library must be specified when accessing items, collections, or tags.');
		}
	}
}

export default verify;